starter_code:
module top(input clk, input rst_n, input async_in, output sync_out);
  // Write code here
endmodule

solution_code:
module top(input clk, input rst_n, input async_in, output sync_out);
  reg s1, s2;
  always @(posedge clk or negedge rst_n)
    if (!rst_n) {s2, s1} <= 2'b00;
    else        {s2, s1} <= {s1, async_in};
  assign sync_out = s2;
endmodule

