module top(input clk, input rst_n, input in, output div3);
  // Write code here
endmodule

solution_code:
module top(input clk, input rst_n, input in, output div3);
  reg [1:0] rem;
  always @(posedge clk or negedge rst_n)
    if (!rst_n) rem <= 2'd0;
    else case ({rem, in})
      3'b00_0: rem <= 2'd0; 3'b00_1: rem <= 2'd1;
      3'b01_0: rem <= 2'd2; 3'b01_1: rem <= 2'd0;
      3'b10_0: rem <= 2'd1; 3'b10_1: rem <= 2'd2;
      default: rem <= 2'd0;
    endcase
  assign div3 = (rem == 2'd0);
endmodule

starter_code:
module top(input [7:0] data, output [3:0] count);
  // Write code here
endmodule

solution_code:
module top(input [7:0] data, output [3:0] count);
  integer i;
  reg [3:0] c;
  always @(*) begin
    c = 4'd0;
    for (i = 0; i < 8; i = i + 1) c = c + data[i];
  end
  assign count = c;
endmodule

