solution_code:
module top(input [7:0] data, output reg [2:0] idx, output reg valid);
  integer i;
  always @(*) begin
    idx = 3'd0; valid = 1'b0;
    for (i = 7; i >= 0; i = i - 1)
      if (data[i]) begin idx = i[2:0]; valid = 1'b1; end
  end
endmodule

