  // Write code here
endmodule

solution_code:
module top(input clk, input rst_n, input in_valid, input [7:0] in_data, input out_ready, output in_ready, output out_valid, output [7:0] out_data);
  reg full;
  reg [7:0] buf_data;
  assign in_ready  = !full;
  assign out_valid = full;
  assign out_data  = buf_data;
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin full <= 1'b0; buf_data <= 8'd0; end
    else begin
      if (in_valid && in_ready) begin buf_data <= in_data; full <= 1'b1; end
      else if (out_valid && out_ready) full <= 1'b0;
    end
  end
endmodule

