starter_code:
module top(input [3:0] req, output [3:0] gnt);
  // Write code here
endmodule

solution_code:
module top(input [3:0] req, output [3:0] gnt);
  assign gnt[0] = req[0];
  assign gnt[1] = req[1] & ~req[0];
  assign gnt[2] = req[2] & ~req[1] & ~req[0];
  assign gnt[3] = req[3] & ~req[2] & ~req[1] & ~req[0];
endmodule
